package com.chaobo.scm.supplier.interfaces.web;import com.chaobo.scm.common.api.*;import com.chaobo.scm.supplier.application.quality.*;import jakarta.servlet.http.*;import jakarta.validation.*;import jakarta.validation.constraints.*;import org.springframework.web.bind.annotation.*;
@RestController @RequestMapping("/internal/supplier/v1/quality/events")public class QualitySourceEventController{private final QualitySourceEventConsumerApplicationService service;public QualitySourceEventController(QualitySourceEventConsumerApplicationService service){this.service=service;}@PostMapping public ApiResponse<Void> consume(@Valid @RequestBody Request body,HttpServletRequest request){String source=request.getHeader("X-Source-System");service.consume(new QualitySourceEvent(source,request.getHeader("X-Event-Code"),body.eventType(),body.supplierId(),body.sourceNo(),body.issueType(),body.severity(),body.description()));return ApiResponse.success(null,request.getHeader("X-Request-Id"),request.getHeader("X-Trace-Id"));}public record Request(@NotBlank String eventType,@Positive long supplierId,@NotBlank String sourceNo,@NotBlank String issueType,@Min(1)@Max(4)int severity,@NotBlank String description){}}
